      options: [{ id: `A`, text: `y = −2x + t + 23` }, { id: `B`, text: `y = 2x + t + 23` }, { id: `C`, text: `y = −(23/17)x + t + 46` }, { id: `D`, text: `y = (23/17)x + t + 46` }],
